// src/App.js
import React, { useState, useEffect } from "react";
import { onAuthChange, logoutUser } from "./utils/firebase";
import LandingPage   from "./pages/LandingPage";
import PracticePage  from "./pages/PracticePage";
import ResultsPage   from "./pages/ResultsPage";
import DashboardPage from "./pages/DashboardPage";
import "./App.css";

export default function App() {
  const [page,         setPage]         = useState("landing");
  const [analysisData, setAnalysisData] = useState(null);
  const [user,         setUser]         = useState(undefined); // undefined = still loading

  // Listen to Firebase auth state
  useEffect(() => {
    const unsub = onAuthChange((firebaseUser) => {
      setUser(firebaseUser); // null = logged out, object = logged in
    });
    return () => unsub();
  }, []);

  const navigate = (newPage, data = null) => {
    // If trying to access a protected page without being logged in,
    // stay on landing — LandingPage will open the auth modal
    if (!user && newPage !== "landing") {
      setPage("landing");
      return;
    }
    if (data) setAnalysisData(data);
    setPage(newPage);
    window.scrollTo(0, 0);
  };

  const handleLogout = async () => {
    await logoutUser();
    setPage("landing");
    setAnalysisData(null);
  };

  // Still checking auth state — show nothing briefly
  if (user === undefined) {
    return (
      <div style={{ minHeight: "100vh", display: "flex", alignItems: "center", justifyContent: "center" }}>
        <div className="spinner" />
      </div>
    );
  }

  return (
    <div className="app">
      {page === "landing"   && <LandingPage   navigate={navigate} user={user} onLogout={handleLogout} />}
      {page === "practice"  && <PracticePage  navigate={navigate} />}
      {page === "results"   && <ResultsPage   results={analysisData} navigate={navigate} />}
      {page === "dashboard" && <DashboardPage navigate={navigate} user={user} />}
    </div>
  );
}
